StructuredTextModel.Text:
CU_R(Clk := CU);
Reset_R(Clk := Reset);
Sub_R(Clk := Substract);

Q := FALSE;

IF (CV < PV) THEN
	;
ELSE
	Q := TRUE;
END_IF;

// Check if multiplier value is larger than one
IF (MP <= 0) THEN
	Add_Val := 1;
ELSE
	Add_Val := MP;
END_IF;
// Add multiplier value, or one, to the count
IF (CU_R.Q) THEN
	CV := CV + Add_Val;
END_IF;

// Remove 1 from count upon request
IF (Sub_R.Q) THEN
	CV := CV-1;
END_IF;

IF (Reset_R.Q) THEN
	CV := 0;
END_IF;
